mapper.insert:
insert into tbl_gallery (
    member_id, title, description, cover_image, allow_comment, show_similar, status
) values (
    #{memberId}, #{title}, #{description}, #{coverImage}, coalesce(#{allowComment}, true), coalesce(#{showSimilar}, true), 'EXHIBITING'
)

insert into tbl_gallery_work (
    gallery_id, work_id, sort_order
) values (
    #{galleryId}, #{workId}, 0
)

mapper.update:
update tbl_gallery
set
    work_count = (
        select count(*)
        from tbl_gallery_work
        where gallery_id = #{galleryId}
    ),
    updated_datetime = now()
where id = #{galleryId}
